def calculate_trainable_parameters(model):
    trainable_params = 0
    total_params = 0
    for name, param in model.named_parameters():
        num_elements = param.numel()
        total_params += num_elements
        if param.requires_grad:
            trainable_params += num_elements

    percentage = (trainable_params / total_params) * 100 if total_params > 0 else 0.0
    return {
        "trainable_parameters": trainable_params,
        "total_parameters": total_params,
        "percentage_trainable": round(percentage, 4)
    }

class ChatDatasetFormatter:
    def __init__(self, system_prompt: str = "You are a helpful assistant."):
        self.system_prompt = system_prompt

    def format_entry(self, user_message: str, assistant_response: str) -> str:
        return (
            f"<s>[INST] <<SYS>>\n{self.system_prompt}\n<</SYS>>\n\n"
            f"{user_message} [/INST] {assistant_response} </s>"
        )

    def format_batch(self, conversations: list[dict]) -> list[str]:
        formatted = []
        for conv in conversations:
            user = conv.get("user", "")
            assistant = conv.get("assistant", "")
            formatted.append(self.format_entry(user, assistant))
        return formatted

class MathematicalError(Exception):
    pass

def safe_divide(numerator: float, denominator: float) -> float:
    try:
        return numerator / denominator
    except ZeroDivisionError as exc:
        err = MathematicalError("Failed to calculate the ratio due to a zero divisor.")
        err.add_note(f"Attempted division: {numerator} divided by {denominator}.")
        raise err from exc

def mask_pad_tokens(token_ids: list[int], pad_token_id: int) -> list[int]:
    return [token if token != pad_token_id else -100 for token in token_ids]

def mask_batch_pad_tokens(batch_token_ids: list[list[int]], pad_token_id: int) -> list[list[int]]:
    return [mask_pad_tokens(seq, pad_token_id) for seq in batch_token_ids]

from typing import Iterator, List, Any

def chunk_dataset(dataset: List[Any], chunk_size: int) -> Iterator[List[Any]]:
    if chunk_size <= 0:
        raise ValueError("Chunk size must be a positive integer.")
    for i in range(0, len(dataset), chunk_size):
        yield dataset[i:i + chunk_size]

