@contextmanager
def measure_execution_time(step_name: str) -> Iterator[dict]:
    metrics = {"elapsed_time": 0.0}
    start_time = time.perf_counter()
    try:
        yield metrics
    finally:
        end_time = time.perf_counter()
        metrics["elapsed_time"] = end_time - start_time
        print(f"Step '{step_name}' completed in {metrics['elapsed_time']:.6f} seconds.")

