import time
from functools import wraps
from typing import Callable, Any

def retry_with_backoff(max_retries: int = 3, initial_delay: float = 1.0, backoff_factor: float = 2.0):
    def decorator(func: Callable[..., Any]) -> Callable[..., Any]:
        @wraps(func)
        def wrapper(*args, **kwargs) -> Any:
            delay = initial_delay
            for attempt in range(max_retries):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_retries - 1:
                        raise e
                    time.sleep(delay)
                    delay *= backoff_factor
        return wrapper
    return decorator

import json
from typing import List, Tuple

def validate_instruction_dataset(jsonl_filepath: str) -> Tuple[bool, List[str]]:
    errors = []
    required_keys = {"instruction", "input", "output"}

    with open(jsonl_filepath, "r", encoding="utf-8") as f:
        for idx, line in enumerate(f, start=1):
            if not line.strip():
                continue
            try:
                data = json.loads(line)
                if not isinstance(data, dict):
                    errors.append(f"Line {idx}: Must be a JSON object.")
                    continue
                missing = required_keys - data.keys()
                if missing:
                    errors.append(f"Line {idx}: Missing keys: {missing}.")
                for key in required_keys:
                    if key in data and not isinstance(data[key], str):
                        errors.append(f"Line {idx}: Key '{key}' must be a string.")
            except json.JSONDecodeError as e:
                errors.append(f"Line {idx}: Invalid JSON syntax. Error: {e}")

    return len(errors) == 0, errors

class ConfigurationError(Exception):
    """Custom exception raised for errors in application configuration."""
    def __init__(self, message: str):
        super().__init__(message)


def parse_hyperparameters(config_dict: dict) -> dict:
    """Parses and validates hyperparameter configurations."""
    try:
        learning_rate = float(config_dict["learning_rate"])
        batch_size = int(config_dict["batch_size"])
        return {"learning_rate": learning_rate, "batch_size": batch_size}
    except KeyError as exc:
        raise ConfigurationError("Missing required training hyperparameter key.") from exc
    except ValueError as exc:
        raise ConfigurationError("Invalid numeric type provided for hyperparameter.") from exc


# Example usage
try:
    bad_config = {"learning_rate": "invalid_float", "batch_size": 32}
    parse_hyperparameters(bad_config)
except ConfigurationError as error:
    print(f"Caught expected error: {error}")
    print(f"Original cause: {repr(error.__cause__)}")

import json
import logging
from typing import List, Dict, Any

logging.basicConfig(level=logging.INFO)

def load_and_validate_jsonl(file_path: str) -> List[Dict[str, str]]:
    """
    Reads a JSON Lines (.jsonl) file and validates each entry.
    Each entry must be a valid JSON object containing 'instruction' and 'output' keys.
    """
    valid_entries = []

    with open(file_path, "r", encoding="utf-8") as f:
        for line_number, line in enumerate(f, start=1):
            stripped_line = line.strip()
            if not stripped_line:
                continue  # Skip empty lines

            try:
                data = json.loads(stripped_line)
                if not isinstance(data, dict):
                    logging.warning(f"Line {line_number}: Skipped because line is not a JSON object.")
                    continue

                if "instruction" in data and "output" in data:
                    valid_entries.append({
                        "instruction": str(data["instruction"]),
                        "output": str(data["output"])
                    })
                else:
                    logging.warning(f"Line {line_number}: Missing 'instruction' or 'output' fields.")
            except json.JSONDecodeError as err:
                logging.error(f"Line {line_number}: Failed to parse JSON. Error: {err}")

    logging.info(f"Successfully loaded {len(valid_entries)} valid entries.")
    return valid_entries

from typing import Dict, Optional

class PromptFormatter:
    @staticmethod
    def to_alpaca(instruction: str, output: str, context: Optional[str] = None) -> str:
        if context and context.strip():
            return (f"### Instruction:\n{instruction.strip()}\n\n"
                    f"### Input:\n{context.strip()}\n\n"
                    f"### Response:\n{output.strip()}")
        return f"### Instruction:\n{instruction.strip()}\n\n### Response:\n{output.strip()}"

    @staticmethod
    def to_chatml(instruction: str, output: str, context: Optional[str] = None) -> str:
        user_content = instruction.strip()
        if context and context.strip():
            user_content = f"{user_content}\n\nContext:\n{context.strip()}"
        return (f"<|im_start|>user\n{user_content}<|im_end|>\n"
                f"<|im_start|>assistant\n{output.strip()}<|im_end|>")

    @staticmethod
    def to_llama3(instruction: str, output: str, context: Optional[str] = None) -> str:
        user_content = instruction.strip()
        if context and context.strip():
            user_content = f"{user_content}\n\n{context.strip()}"
        return (f"<|begin_of_text|><|start_header_id|>user<|end_header_id|>\n\n{user_content}<|eot_id|>"
                f"<|start_header_id|>assistant<|end_header_id|>\n\n{output.strip()}<|eot_id|>")

import json
from pathlib import Path
from typing import List, Dict, Union

def parse_and_validate_jsonl(file_path: Union[str, Path]) -> List[Dict[str, str]]:
    valid_records = []
    path = Path(file_path)

    if not path.exists():
        raise FileNotFoundError(f"Target path {file_path} not found.")

    with open(path, "r", encoding="utf-8") as f:
        for line_num, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue
            try:
                data = json.loads(line)
                instruction = data.get("instruction", "").strip()
                output = data.get("output", "").strip()

                if not instruction or not output:
                    print(f"Line {line_num} skipped: Missing required instruction or output values.")
                    continue

                valid_records.append({
                    "instruction": instruction,
                    "input": data.get("input", "").strip(),
                    "output": output,
                    "category": data.get("category", "general")
                })
            except json.JSONDecodeError as e:
                print(f"Line {line_num} skipped: Invalid JSON structure - {e}")

    print(f"Successfully parsed {len(valid_records)} valid records.")
    return valid_records

from typing import List, Dict, Any

def convert_sharegpt_to_alpaca(sharegpt_data: List[Dict[str, Any]]) -> List[Dict[str, str]]:
    flattened_dataset = []

    for idx, conversation in enumerate(sharegpt_data):
        dialogue = conversation.get("conversations", [])
        if not dialogue:
            continue

        context_history = []
        for i, turn in enumerate(dialogue):
            role = turn.get("from")
            value = turn.get("value", "").strip()

            if role == "human":
                instruction = value
                # If there was a previous context, store it as input
                input_context = "\n".join(context_history) if context_history else ""

                # Search for corresponding assistant response
                if i + 1 < len(dialogue) and dialogue[i+1].get("from") == "gpt":
                    output = dialogue[i+1].get("value", "").strip()

                    flattened_dataset.append({
                        "instruction": instruction,
                        "input": input_context,
                        "output": output
                    })
                # Track this human input in context history
                context_history.append(f"User: {value}")
            elif role == "gpt":
                context_history.append(f"Assistant: {value}")

    return flattened_dataset

import torch
from torch.utils.data import Dataset

class InstructionDataset(Dataset):
    def __init__(self, data, tokenizer, max_length=512):
        self.data = data
        self.tokenizer = tokenizer
        self.max_length = max_length

    def __len__(self):
        return len(self.data)

    def __getitem__(self, idx):
        item = self.data[idx]
        text = item["text"]
        encoding = self.tokenizer(
            text,
            truncation=True,
            max_length=self.max_length,
            padding="max_length",
            return_tensors="pt"
        )
        input_ids = encoding["input_ids"].squeeze(0)
        attention_mask = encoding["attention_mask"].squeeze(0)
        labels = torch.cat([
            input_ids[1:], 
            torch.tensor([self.tokenizer.pad_token_id])
        ])
        pad_positions = (labels == self.tokenizer.pad_token_id).nonzero(as_tuple=True)[0]
        if len(pad_positions) > 1:
            labels[pad_positions[1:]] = -100
        return {
            "input_ids": input_ids,
            "attention_mask": attention_mask,
            "labels": labels
        }

import hashlib
from dataclasses import dataclass, field
from typing import Dict

@dataclass
class InstructionExample:
    instruction: str
    output: str
    input: str = ""
    category: str = "general"
    metadata: Dict = field(default_factory=dict)

    def __post_init__(self):
        self.instruction = self.instruction.strip()
        self.output = self.output.strip()
        self.input = self.input.strip()
        content = f"{self.instruction}{self.input}{self.output}"
        self.metadata["id"] = hashlib.md5(content.encode()).hexdigest()[:12]

    def to_prompt(self, template: str = "alpaca") -> str:
        if template == "alpaca":
            if self.input:
                return (
                    f"### Instruction:\n{self.instruction}\n\n"
                    f"### Input:\n{self.input}\n\n"
                    f"### Response:\n{self.output}"
                )
            return f"### Instruction:\n{self.instruction}\n\n### Response:\n{self.output}"
        elif template == "chatml":
            user_content = self.instruction
            if self.input:
                user_content = f"{self.instruction}\n\nContext:\n{self.input}"
            return (
                f"<|im_start|>user\n{user_content}<|im_end|>\n"
                f"<|im_start|>assistant\n{self.output}<|im_end|"
            )
        elif template == "llama":
            user_content = self.instruction
            if self.input:
                user_content = f"{self.instruction}\n\n{self.input}"
            return (
                f"<|begin_of_text|><|start_header_id|>user<|end_header_id|>\n\n"
                f"{user_content}<|eot_id|><|start_header_id|>assistant<|end_header_id|>\n\n"
                f"{self.output}<|eot_id|"
            )
        else:
            raise ValueError(f"Unknown template: {template}")

import torch
from typing import List, Dict

class DynamicInstructionCollator:
    def __init__(self, tokenizer, pad_to_multiple_of: int = 8):
        self.tokenizer = tokenizer
        self.pad_to_multiple_of = pad_to_multiple_of

    def __call__(self, batch: List[Dict[str, str]]) -> Dict[str, torch.Tensor]:
        texts = [item["text"] for item in batch]
        encoding = self.tokenizer(
            texts,
            padding=True,
            truncation=True,
            return_tensors="pt"
        )
        input_ids = encoding["input_ids"]
        attention_mask = encoding["attention_mask"]
        seq_len = input_ids.shape[1]
        if self.pad_to_multiple_of and seq_len % self.pad_to_multiple_of != 0:
            pad_len = self.pad_to_multiple_of - (seq_len % self.pad_to_multiple_of)
            input_ids = torch.nn.functional.pad(
                input_ids, (0, pad_len), value=self.tokenizer.pad_token_id
            )
            attention_mask = torch.nn.functional.pad(
                attention_mask, (0, pad_len), value=0
            )
        labels = torch.cat([
            input_ids[:, 1:], 
            torch.full((input_ids.shape[0], 1), self.tokenizer.pad_token_id)
        ], dim=1)
        labels_processed = labels.clone()
        for i in range(labels.shape[0]):
            pad_positions = (labels[i] == self.tokenizer.pad_token_id).nonzero(as_tuple=True)[0]
            if len(pad_positions) > 1:
                labels_processed[i, pad_positions[1:]] = -100
        return {
            "input_ids": input_ids,
            "attention_mask": attention_mask,
            "labels": labels_processed
        }
